// BatchDeleteUsers is the resolver for the batchDeleteUsers field. The
// currently authenticated user is silently filtered out before the store call,
// mirroring the single deleteUser self-protection rule.
func (r *mutationResolver) BatchDeleteUsers(ctx context.Context, ids []string) (int, error) {
	cu, ok := auth.UserFromContext(ctx)
	if !ok {
		return 0, fmt.Errorf("authentication required")
	}
	targetIDs := make([]string, 0, len(ids))
	for _, id := range ids {
		if id == cu.ID {
			continue
		}
		targetIDs = append(targetIDs, id)
	}
	if len(targetIDs) == 0 {
		return 0, nil
	}
	avatars, err := r.Store.GetUserAvatarPathsByIDs(ctx, targetIDs)
	if err != nil {
		return 0, fmt.Errorf("load target users: %w", err)
	}
	n, err := r.Store.BatchDeleteUsers(ctx, targetIDs)
	if err != nil {
		return 0, err
	}
	if r.AvatarDir != "" {
		for _, avatar := range avatars {
			full := filepath.Join(r.AvatarDir, avatar)
			if rmErr := os.Remove(full); rmErr != nil && !errors.Is(rmErr, os.ErrNotExist) {
				graphLogger.Warn("failed to remove avatar file on batch user delete", "path", full, "error", rmErr)
			}
		}
	}
	return int(n), nil
}

// BatchAddRoomMembers is the resolver for the batchAddRoomMembers field.
func (r *mutationResolver) BatchAddRoomMembers(ctx context.Context, roomID string, members []*model.RoomMemberInput) (*model.Room, error) {
	inputs := make([]store.RoomMemberInput, 0, len(members))
	for _, m := range members {
		memberType := device.RoomMemberType(m.MemberType)
		if memberType != device.RoomMemberDevice && memberType != device.RoomMemberGroup {
			return nil, fmt.Errorf("%w %q: must be %q or %q", device.ErrInvalidRoomMemberType, m.MemberType, device.RoomMemberDevice, device.RoomMemberGroup)
		}
		if memberType == device.RoomMemberGroup {
			parent := entityRef{kind: "room", id: roomID}
			child := entityRef{kind: "group", id: m.MemberID}
			if err := r.checkCircularDependency(ctx, parent, child); err != nil {
				return nil, err
			}
		}
		inputs = append(inputs, store.RoomMemberInput{
			MemberType: memberType,
			MemberID:   m.MemberID,
		})
	}
	if _, err := r.Store.BatchAddRoomMembers(ctx, roomID, inputs); err != nil {
		return nil, err
	}
	r.publishRoomMembershipChanged()
	rm, err := r.Store.GetRoom(ctx, roomID)
	if err != nil {
		return nil, err
	}
	return mapRoom(ctx, r.StateReader, r.Store, rm), nil
}

// BatchAddGroupDevices is the resolver for the batchAddGroupDevices field.
// Devices already members of the group are silently skipped. Returns the
// updated group.
func (r *mutationResolver) BatchAddGroupDevices(ctx context.Context, groupID string, deviceIds []string) (*model.Group, error) {
	if _, err := r.Store.BatchAddGroupDevices(ctx, groupID, deviceIds); err != nil {
		return nil, err
	}
	g, err := r.Store.GetGroup(ctx, groupID)
	if err != nil {
		return nil, err
	}
	members, err := r.Store.ListGroupMembers(ctx, groupID)
	if err != nil {
		return nil, err
	}
	return mapGroup(ctx, r.StateReader, r.Store, g, members), nil
}

// CreateEffect is the resolver for the createEffect field.
func (r *mutationResolver) CreateEffect(ctx context.Context, input model.CreateEffectInput) (*model.Effect, error) {
	nativeName := input.NativeName.Value()
	if err := validateEffectInput(input.Kind, nativeName, input.Loop, input.DurationMs, input.Tracks); err != nil {
		return nil, err
	}

	tracks, err := buildEffectTrackInputs(input.Tracks)
	if err != nil {
		return nil, err
	}

	effectID := uuid.New().String()
	if _, err := r.Store.CreateEffect(ctx, store.CreateEffectParams{
		ID:         effectID,
		Name:       input.Name,
		Icon:       input.Icon.Value(),
		Kind:       effectKindFromModel(input.Kind),
		NativeName: nativeName,
		Loop:       input.Loop,
		DurationMs: input.DurationMs,
		CreatedBy:  currentUserID(ctx),
		Tracks:     tracks,
	}); err != nil {
		return nil, err
	}

	row, err := r.Store.GetEffect(ctx, effectID)
	if err != nil {
		return nil, err
	}
	return mapEffect(row), nil
}

// UpdateEffect is the resolver for the updateEffect field.
func (r *mutationResolver) UpdateEffect(ctx context.Context, input model.UpdateEffectInput) (*model.Effect, error) {
	existing, err := r.Store.GetEffect(ctx, input.ID)
	if err != nil {
		return nil, fmt.Errorf("effect %q not found: %w", input.ID, err)
	}

	tracksValue, tracksGiven := input.Tracks.ValueOK()
	if tracksGiven {
		loop := existing.Loop
		if v, ok := input.Loop.ValueOK(); ok && v != nil {
			loop = *v
		}
		duration := existing.DurationMs
		if v, ok := input.DurationMs.ValueOK(); ok && v != nil {
			duration = *v
		}
		nativeName := input.NativeName.Value()
		if err := validateEffectInput(modelKindFromStore(existing.Kind), nativeName, loop, duration, tracksValue); err != nil {
			return nil, err
		}
	}

	params := store.UpdateEffectParams{}
	if name, ok := input.Name.ValueOK(); ok && name != nil {
		params.Name = name
	}
	if icon, ok := input.Icon.ValueOK(); ok {
		params.SetIcon = true
		params.Icon = icon
	}
	if loop, ok := input.Loop.ValueOK(); ok && loop != nil {
		params.Loop = loop
	}
	if duration, ok := input.DurationMs.ValueOK(); ok && duration != nil {
		params.DurationMs = duration
	}
	if nativeName, ok := input.NativeName.ValueOK(); ok {
		params.SetNativeName = true
		params.NativeName = nativeName
	}
	if _, err := r.Store.UpdateEffect(ctx, input.ID, params); err != nil {
		return nil, err
	}

	if tracksGiven {
		newTracks, err := buildEffectTrackInputs(tracksValue)
		if err != nil {
			return nil, err
		}
		if err := r.Store.SaveEffectTracks(ctx, input.ID, newTracks); err != nil {
			return nil, err
		}
	}

	row, err := r.Store.GetEffect(ctx, input.ID)
	if err != nil {
		return nil, err
	}
	return mapEffect(row), nil
}

