// Settings is the resolver for the settings field. Server-internal keys
// (auth.IsInternalSettingKey) are filtered out so callers cannot exfiltrate
// secrets like the JWT signing key — see the doc comment on IsInternalSettingKey.
func (r *queryResolver) Settings(ctx context.Context) ([]*model.Setting, error) {
	settings, err := r.Store.ListSettings(ctx)
	if err != nil {
		return nil, err
	}
	result := make([]*model.Setting, 0, len(settings))
	for _, s := range settings {
		if auth.IsInternalSettingKey(s.Key) {
			continue
		}
		result = append(result, &model.Setting{Key: s.Key, Value: s.Value})
	}
	return result, nil
}

// Logs is the resolver for the logs field.
func (r *queryResolver) Logs(ctx context.Context, search *string, limit *int) ([]*model.LogEntry, error) {
	entries := r.LogBuffer.Entries()

	var result []*model.LogEntry
	for i := len(entries) - 1; i >= 0; i-- {
		e := entries[i]
		if search != nil && *search != "" {
			if !containsFold(e.Message, *search) && !attrsContainFold(e.Attrs, *search) {
				continue
			}
		}
		result = append(result, mapLogEntry(e))
		if limit != nil && len(result) >= *limit {
			break
		}
	}

	for i, j := 0, len(result)-1; i < j; i, j = i+1, j-1 {
		result[i], result[j] = result[j], result[i]
	}

	return result, nil
}

// Activity is the resolver for the activity field.
func (r *queryResolver) Activity(ctx context.Context, filter *model.ActivityFilter) ([]*model.ActivityEvent, error) {
	q := store.ActivityQuery{Limit: 500}
	if filter != nil {
		if types, ok := filter.Types.ValueOK(); ok {
			q.Types = types
		}
		if did, ok := filter.DeviceID.ValueOK(); ok && did != nil {
			q.DeviceID = did
		}
		if rid, ok := filter.RoomID.ValueOK(); ok && rid != nil {
			q.RoomID = rid
		}
		if since, ok := filter.Since.ValueOK(); ok && since != nil {
			q.Since = since
		}
		if adv, ok := filter.Advanced.ValueOK(); ok && adv != nil {
			q.Advanced = *adv
		}
		if lim, ok := filter.Limit.ValueOK(); ok && lim != nil && *lim > 0 {
			q.Limit = *lim
		}
		if before, ok := filter.Before.ValueOK(); ok && before != nil && *before != "" {
			n, err := strconv.ParseInt(*before, 10, 64)
			if err != nil {
				return nil, fmt.Errorf("invalid before cursor %q: %w", *before, err)
			}
			q.Before = &n
		}
	}
	rows, err := r.Store.QueryActivityEvents(ctx, q)
	if err != nil {
		return nil, err
	}
	result := make([]*model.ActivityEvent, len(rows))
	for i, row := range rows {
		result[i] = mapActivityEvent(row)
	}
	return result, nil
}

// Alarms is the resolver for the alarms field. Returns grouped alarms ordered
// most-recently-raised first. Filtering is performed in Go over the grouped
// projection so the frontend can freely combine severity/kind/source/since
// without the SQL layer having to understand grouping.
func (r *queryResolver) Alarms(ctx context.Context, filter *model.AlarmFilter) ([]*model.Alarm, error) {
	list, err := r.Resolver.Alarms.ListActive(ctx)
	if err != nil {
		return nil, err
	}

	var (
		wantSeverities map[store.AlarmSeverity]struct{}
		wantKinds      map[store.AlarmKind]struct{}
		wantSources    map[string]struct{}
		since          *time.Time
	)
	if filter != nil {
		if sevs, ok := filter.Severities.ValueOK(); ok && len(sevs) > 0 {
			wantSeverities = make(map[store.AlarmSeverity]struct{}, len(sevs))
			for _, s := range sevs {
				wantSeverities[severityFromModel(s)] = struct{}{}
			}
		}
		if ks, ok := filter.Kinds.ValueOK(); ok && len(ks) > 0 {
			wantKinds = make(map[store.AlarmKind]struct{}, len(ks))
			for _, k := range ks {
				wantKinds[kindFromModel(k)] = struct{}{}
			}
		}
		if srcs, ok := filter.Sources.ValueOK(); ok && len(srcs) > 0 {
			wantSources = make(map[string]struct{}, len(srcs))
			for _, s := range srcs {
				wantSources[s] = struct{}{}
			}
		}
		if t, ok := filter.Since.ValueOK(); ok {
			since = t
		}
	}

	result := make([]*model.Alarm, 0, len(list))
	for _, a := range list {
		if wantSeverities != nil {
			if _, ok := wantSeverities[a.Severity]; !ok {
				continue
			}
		}
		if wantKinds != nil {
			if _, ok := wantKinds[a.Kind]; !ok {
				continue
			}
		}
		if wantSources != nil {
			if _, ok := wantSources[a.Source]; !ok {
				continue
			}
		}
		if since != nil && a.LastRaisedAt.Before(*since) {
			continue
		}
		result = append(result, mapAlarm(a))
	}
	return result, nil
}

// SetupStatus is the resolver for the setupStatus field. Whitelisted — callable
